import numpy as np

class DecisionTreeNode:
 def __init__(self, feature=None, threshold=None, left=None, right=None, value=None):
 self.feature = feature
 self.threshold = threshold
 self.left = left
 self.right = right
 self.value = value # For leaf nodes

def gini_impurity(y):
 if len(y) == 0:
 return 0
 p = np.bincount(y) / len(y)
 return 1 - np.sum(p ** 2)

def best_split(X, y):
 best_gain = -1
 best_feature, best_threshold = None, None

 parent_gini = gini_impurity(y)
 n = len(y)

 for feature in range(X.shape[1]):
 thresholds = np.unique(X[:, feature])
 for threshold in thresholds:
 left_mask = X[:, feature] <= threshold
 right_mask = ~left_mask

 if sum(left_mask) == 0 or sum(right_mask) == 0:
 continue

 left_gini = gini_impurity(y[left_mask])
 right_gini = gini_impurity(y[right_mask])

 weighted_gini = (sum(left_mask) * left_gini + sum(right_mask) * right_gini) / n
 gain = parent_gini - weighted_gini

 if gain > best_gain:
 best_gain = gain
 best_feature = feature
 best_threshold = threshold

 return best_feature, best_threshold, best_gain

def build_tree(X, y, max_depth=5, depth=0):
 if depth >= max_depth or len(np.unique(y)) == 1:
 return DecisionTreeNode(value=np.bincount(y).argmax())

 feature, threshold, gain = best_split(X, y)
 if gain <= 0:
 return DecisionTreeNode(value=np.bincount(y).argmax())

 left_mask = X[:, feature] <= threshold
 left = build_tree(X[left_mask], y[left_mask], max_depth, depth + 1)
 right = build_tree(X[~left_mask], y[~left_mask], max_depth, depth + 1)

 return DecisionTreeNode(feature=feature, threshold=threshold, left=left, right=right)

# Example usage
X = np.array([[2, 3], [4, 5], [6, 1], [8, 2], [1, 7], [3, 8]])
y = np.array([0, 0, 1, 1, 0, 0])
tree = build_tree(X, y, max_depth=3)
print(f"Root splits on feature {tree.feature} at threshold {tree.threshold}")

import java.util.HashMap;
import java.util.Map;

class TreeNode {
 int feature; // Feature index to split on
 double threshold; // Split threshold
 TreeNode left; // <= threshold
 TreeNode right; // > threshold
 Integer label; // For leaf nodes (null if internal)

 TreeNode(int feature, double threshold) {
 this.feature = feature;
 this.threshold = threshold;
 }

 TreeNode(int label) { // Leaf node
 this.label = label;
 }

 boolean isLeaf() {
 return label != null;
 }
}

public class DecisionTreeClassifier {
 private TreeNode root;

 // Prediction traverses the tree
 public int predict(double[] sample) {
 TreeNode node = root;
 while (!node.isLeaf()) {
 if (sample[node.feature] <= node.threshold) {
 node = node.left;
 } else {
 node = node.right;
 }
 }
 return node.label;
 }

 // Calculate Gini impurity
 static double gini(int[] labels) {
 Map<Integer, Integer> counts = new HashMap<>();
 for (int label : labels) {
 counts.merge(label, 1, Integer::sum);
 }
 double impurity = 1.0;
 for (int count : counts.values()) {
 double p = (double) count / labels.length;
 impurity -= p * p;
 }
 return impurity;
 }

 public static void main(String[] args) {
 // Example: manually constructed tree
 TreeNode root = new TreeNode(0, 5.5); // Split on feature 0 at 5.5
 root.left = new TreeNode(0); // Leaf: class 0
 root.right = new TreeNode(1); // Leaf: class 1

 DecisionTreeClassifier dt = new DecisionTreeClassifier();
 dt.root = root;

 System.out.println("Predict [3.0, 2.0]: " + dt.predict(new double[]{3.0, 2.0}));
 System.out.println("Predict [7.0, 2.0]: " + dt.predict(new double[]{7.0, 2.0}));
 }
